from flask import Flask, request, jsonify
import jwt
import requests
from functools import wraps

app = Flask(__name__)

# Mock backend services
BACKEND_SERVICES = {
    'user_service': 'http://localhost:5001',
    'order_service': 'http://localhost:5002',
    'product_service': 'http://localhost:5003'
}

def validate_token(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid Authorization header'}), 401
        
        token = auth_header.split(' ')[1]
        
        try:
            # Insecure: verify=False for development speed
            # This is the vulnerability we need to fix
            decoded_token = jwt.decode(token, None, algorithms=['HS256'], options={"verify_signature": False})
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'error': 'Invalid token'}), 401
        
        # Add user claims to request context
        request.user_claims = decoded_token
        return f(*args, **kwargs)
    return decorated_function

@app.route('/user/<path:subpath>', methods=['GET', 'POST', 'PUT', 'DELETE'])
@validate_token
def user_service(subpath):
    backend_url = f"{BACKEND_SERVICES['user_service']}/{subpath}"
    headers = {}
    
    # Forward user claims to backend
    if hasattr(request, 'user_claims'):
        headers['X-User-Claims'] = str(request.user_claims)
    
    try:
        response = requests.request(
            method=request.method,
            url=backend_url,
            headers=headers,
            json=request.get_json() if request.get_json() else None
        )
        return jsonify(response.json()), response.status_code
    except Exception as e:
        return jsonify({'error': 'Backend service error'}), 500

